function statusConfig(status) {
  switch (status) {
    case STATUS.CONFORME:
      return { label: "Conforme", icon: Check, bg: "bg-[#1F5A4A]", text: "text-[#1F5A4A]", hex: "#1F5A4A" };
    case STATUS.NAO_CONFORME:
      return { label: "Não conforme", icon: X, bg: "bg-[#A13D2B]", text: "text-[#A13D2B]", hex: "#A13D2B" };
    case STATUS.NA:
      return { label: "Não se aplica", icon: MinusCircle, bg: "bg-[#8B7355]", text: "text-[#8B7355]", hex: "#8B7355" };
    default:
      return null;
  }
}

function romanize(n) {
  const map = ["I", "II", "III", "IV", "V", "VI", "VII", "VIII", "IX", "X", "XI", "XII"];
  return map[n] || String(n + 1);
}

function percentualBadge(valor, meta) {
  if (valor === null || Number.isNaN(valor)) return null;
  const dentro = valor >= meta;
  return (
    <span
      className={`font-mono-label text-[11px] uppercase tracking-wider px-2 py-1 border-2 pb-2.5 mb-0
        ${dentro ? "border-[#1F5A4A] text-[#1F5A4A]" : "border-[#A13D2B] text-[#A13D2B]"}`}
    >
      {dentro ? "Dentro da meta" : "Abaixo da meta"}
    </span>
  );
}

function mensagemPendencia({ progresso, responsavel, percentualPreenchido, justificativaBiometriaCompleta }) {
  const pendencias = [];
  if (progresso.respondidos < progresso.total) pendencias.push("todos os itens");
  if (!responsavel.trim()) pendencias.push("nome do responsável");
  if (!percentualPreenchido) pendencias.push("percentual de biometria");
  if (!justificativaBiometriaCompleta) pendencias.push("motivo e ações pactuadas do indicador de biometria (percentual crítico)");
  return "Falta preencher: " + pendencias.join(", ");
}

// ---------- Mock de série histórica (7 meses, 6 hospitais) ----------
// Gerador determinístico simples (sem dependências externas) para dar
// variação plausível e repetível entre os hospitais.
function seededRandom(seed) {
  let s = seed % 2147483647;
  if (s <= 0) s += 2147483646;
  return () => {
    s = (s * 16807) % 2147483647;
    return (s - 1) / 2147483646;
  };
}

