function gerarHistorico(numMeses = 7) {
  const hoje = new Date();
  const historico = {};
  HOSPITAIS.forEach((h, hIdx) => {
    const rand = seededRandom(1000 + hIdx * 37);
    const meses = [];
    // base de comportamento distinta por hospital, pra ficar visualmente legível
    const baseline = [94, 91, 88, 96, 85, 92][hIdx] ?? 90;
    for (let i = numMeses - 1; i >= 0; i--) {
      const d = new Date(hoje.getFullYear(), hoje.getMonth() - i, 1);
      const variacao = (rand() - 0.5) * 10;
      let pct = Math.round((baseline + variacao) * 10) / 10;
      pct = Math.max(70, Math.min(99.5, pct));
      const abaixo = pct < META_BIOMETRIA;
      meses.push({
        mesIndex: d.getMonth(),
        ano: d.getFullYear(),
        label: `${MESES_ABREV[d.getMonth()]}/${String(d.getFullYear()).slice(2)}`,
        percentual: pct,
        abaixoDaMeta: abaixo,
        motivo: abaixo ? MOTIVOS_EXEMPLO[Math.floor(rand() * MOTIVOS_EXEMPLO.length)] : "",
        acoes: abaixo ? ACOES_EXEMPLO[Math.floor(rand() * ACOES_EXEMPLO.length)] : "",
        responsavel: "Equipe UCI " + h.sigla,
        statusItens: ARTIGOS.reduce((acc, item) => {
          const r = rand();
          acc[item.art] = r > 0.85 ? STATUS.NAO_CONFORME : r > 0.78 ? STATUS.NA : STATUS.CONFORME;
          return acc;
        }, {}),
      });
    }
    historico[h.sigla] = meses;
  });
  return historico;
}

const HISTORICO_MOCK = gerarHistorico(7);

function calcularICA(statusItens) {
  let conforme = 0;
  let naoConforme = 0;
  Object.values(statusItens).forEach((s) => {
    if (s === STATUS.CONFORME) conforme++;
    else if (s === STATUS.NAO_CONFORME) naoConforme++;
    // N/A não entra no numerador nem no denominador
  });
  const denominador = conforme + naoConforme;
  if (denominador === 0) return null;
  return Math.round((conforme / denominador) * 1000) / 10;
}

// Série do ICA derivada do mesmo histórico de checklist usado no gráfico de biometria.
function gerarHistoricoICA(historicoChecklist) {
  const resultado = {};
  Object.entries(historicoChecklist).forEach(([sigla, meses]) => {
    resultado[sigla] = meses.map((m) => ({
      mesIndex: m.mesIndex,
      ano: m.ano,
      label: m.label,
      ica: calcularICA(m.statusItens),
      conforme: Object.values(m.statusItens).filter((s) => s === STATUS.CONFORME).length,
      naoConforme: Object.values(m.statusItens).filter((s) => s === STATUS.NAO_CONFORME).length,
      naoAplica: Object.values(m.statusItens).filter((s) => s === STATUS.NA).length,
    }));
  });
  return resultado;
}

