function custoVigenteNoMes(historicoCusto, ano, mesIndex) {
  const dataRef = new Date(ano, mesIndex, 1);
  const candidatos = historicoCusto
    .filter((v) => new Date(v.vigenciaInicio) <= dataRef)
    .sort((a, b) => new Date(b.vigenciaInicio) - new Date(a.vigenciaInicio));
  return candidatos[0] || historicoCusto[0];
}

// Quantidade realizada por mês (7 meses), por tipo x categoria, por hospital — com leve tendência de queda
// em relação à referência, para simular economia em progresso.
function gerarRealizadoMock(referencia, numMeses = 7) {
  const hoje = new Date();
  const realizado = {};
  HOSPITAIS.forEach((h, hIdx) => {
    const rand = seededRandom(9000 + hIdx * 23);
    realizado[h.sigla] = [];
    for (let i = numMeses - 1; i >= 0; i--) {
      const d = new Date(hoje.getFullYear(), hoje.getMonth() - i, 1);
      const fatorMes = {};
      // Cada hospital tem, em média, uma tendência própria (alguns mais econômicos, outros mais gastadores),
      // e dentro disso o mês oscila — o suficiente para que prejuízo apareça de fato em parte dos meses.
      const tendenciaHospital = [0.92, 0.97, 1.02, 0.94, 1.06, 0.99][hIdx] ?? 1;
      TIPOS_REFEICAO.forEach((tipo) => {
        fatorMes[tipo] = {};
        CATEGORIAS_PUBLICO.forEach((cat) => {
          const refQtd = referencia[h.sigla][tipo][cat.id];
          const variacaoMes = (rand() - 0.5) * 0.35; // +/-17,5% de oscilação mensal
          const fator = tendenciaHospital + variacaoMes;
          fatorMes[tipo][cat.id] = Math.max(0, Math.round(refQtd * fator));
        });
      });
      realizado[h.sigla].push({
        mesIndex: d.getMonth(),
        ano: d.getFullYear(),
        label: `${MESES_ABREV[d.getMonth()]}/${String(d.getFullYear()).slice(2)}`,
        quantidades: fatorMes,
      });
    }
  });
  return realizado;
}

