function formatarMoeda(v) {
  return v.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

function calcularEconomiaMes({ referencia, mesRealizado, historicoCusto }) {
  const custoVigente = custoVigenteNoMes(historicoCusto, mesRealizado.ano, mesRealizado.mesIndex);
  const porCategoria = {};
  CATEGORIAS_PUBLICO.forEach((cat) => { porCategoria[cat.id] = { economia: 0, refTotal: 0, realTotal: 0 }; });
  let totalEconomia = 0;

  const detalhePorTipo = TIPOS_REFEICAO.map((tipo) => {
    const linha = { tipo, categorias: {}, custoUnitario: custoVigente.custos[tipo] };
    let economiaTipo = 0;
    CATEGORIAS_PUBLICO.forEach((cat) => {
      const refQtd = referencia[tipo][cat.id];
      const realQtd = mesRealizado.quantidades[tipo][cat.id];
      const diffQtd = refQtd - realQtd;
      const economiaCelula = diffQtd * custoVigente.custos[tipo];
      linha.categorias[cat.id] = { refQtd, realQtd, diffQtd, economiaCelula };
      economiaTipo += economiaCelula;
      porCategoria[cat.id].economia += economiaCelula;
      porCategoria[cat.id].refTotal += refQtd;
      porCategoria[cat.id].realTotal += realQtd;
    });
    linha.economiaTipo = economiaTipo;
    totalEconomia += economiaTipo;
    return linha;
  });

  return { custoVigente, detalhePorTipo, porCategoria, totalEconomia };
}

// Série histórica de economia mensal (R$) por hospital, derivada da referência x realizado x custo vigente.
function gerarHistoricoEconomia() {
  const resultado = {};
  HOSPITAIS.forEach((h) => {
    const referencia = REFERENCIA_MOCK[h.sigla];
    resultado[h.sigla] = REALIZADO_MOCK[h.sigla].map((mes) => {
      const calc = calcularEconomiaMes({ referencia, mesRealizado: mes, historicoCusto: HISTORICO_CUSTO_MOCK });
      return {
        mesIndex: mes.mesIndex,
        ano: mes.ano,
        label: mes.label,
        economia: Math.round(calc.totalEconomia * 100) / 100,
      };
    });
  });
  return resultado;
}

const HISTORICO_ECONOMIA_MOCK = gerarHistoricoEconomia();

// ---------- Gráfico de série histórica (SVG nativo, com pontos clicáveis) ----------
// Genérico: serve para ICA (%), Biometria (%) e Economia (R$), cada um com sua escala.
function GraficoSerieHistorica({
  historico,
  hospitaisFiltrados,
  pontoSelecionado,
  onSelecionarPonto,
  campoValor,
  yMin,
  yMax,
  gridValues,
  formatarTick,
  linhaReferencia,
  labelReferencia,
  corAbaixoReferencia,
  abaixoEhRuim = true,
  ariaLabel,
}) {
  const largura = 760;
  const altura = 420;
  const margem = { top: 20, right: 24, bottom: 36, left: 48 };
  const innerW = largura - margem.left - margem.right;
  const innerH = altura - margem.top - margem.bottom;

  const hospitaisExibidos = hospitaisFiltrados || HOSPITAIS;
  const meses = historico[HOSPITAIS[0].sigla];
  const n = meses.length;

  const x = (i) => margem.left + (i / (n - 1)) * innerW;
  const y = (v) => margem.top + innerH - ((v - yMin) / (yMax - yMin)) * innerH;
  const yRef = linhaReferencia !== undefined ? y(linhaReferencia) : null;

  function corDoPonto(h, valor) {
    if (linhaReferencia === undefined || corAbaixoReferencia === undefined) return h.cor;
    const ruim = abaixoEhRuim ? valor < linhaReferencia : valor > linhaReferencia;
    return ruim ? corAbaixoReferencia : h.cor;
  }

  return (
    <div className="overflow-x-auto">
      <svg viewBox={`0 0 ${largura} ${altura}`} className="w-full min-w-[600px]" role="img" aria-label={ariaLabel}>
        {/* grid horizontal */}
        {gridValues.map((v) => (
          <g key={v}>
            <line x1={margem.left} x2={largura - margem.right} y1={y(v)} y2={y(v)} stroke="#1C1A17" strokeOpacity="0.08" />
            <text x={margem.left - 8} y={y(v)} textAnchor="end" dominantBaseline="middle" className="font-mono-label" fontSize="10" fill="#6B6357">
              {formatarTick(v)}
            </text>
          </g>
        ))}

        {/* linha de referência/meta, se houver */}
        {yRef !== null && (
          <>
            <line x1={margem.left} x2={largura - margem.right} y1={yRef} y2={yRef} stroke={corAbaixoReferencia || "#A13D2B"} strokeWidth="1.5" strokeDasharray="4 3" />
            <text x={largura - margem.right} y={yRef - 6} textAnchor="end" className="font-mono-label" fontSize="10" fill={corAbaixoReferencia || "#A13D2B"}>
              {labelReferencia}
            </text>
          </>
        )}

        {/* eixo x labels */}
        {meses.map((m, i) => (
          <text key={i} x={x(i)} y={altura - 10} textAnchor="middle" className="font-mono-label" fontSize="10" fill="#6B6357">
            {m.label}
          </text>
        ))}

        {/* linhas por hospital (somente os filtrados) */}
        {hospitaisExibidos.map((h) => {
          const dados = historico[h.sigla];
          const pathD = dados
            .filter((d) => campoValor(d) !== null)
            .map((d, i) => `${i === 0 ? "M" : "L"}${x(dados.indexOf(d))},${y(campoValor(d))}`)
            .join(" ");
          return (
            <g key={h.sigla}>
              <path d={pathD} fill="none" stroke={h.cor} strokeWidth={1.75} />
              {dados.map((d, i) => {
                const valor = campoValor(d);
                if (valor === null) return null;
                const isSelected = pontoSelecionado && pontoSelecionado.sigla === h.sigla && pontoSelecionado.idx === i;
                return (
                  <circle
                    key={i}
                    cx={x(i)}
                    cy={y(valor)}
                    r={isSelected ? 6 : 3.5}
                    fill={corDoPonto(h, valor)}
                    stroke={isSelected ? "#1C1A17" : "none"}
                    strokeWidth={isSelected ? 2 : 0}
                    style={{ cursor: "pointer" }}
                    onClick={() => onSelecionarPonto({ sigla: h.sigla, idx: i })}
                  />
                );
              })}
            </g>
          );
        })}
      </svg>
    </div>
  );
}

