// ---------- Gráfico de barras agrupadas (usado pela Economia: 1 grupo por mês, 1 barra por hospital) ----------
function GraficoBarrasAgrupadas({ historico, hospitaisFiltrados, pontoSelecionado, onSelecionarPonto, campoValor, formatarTick, ariaLabel }) {
  const hospitaisExibidos = hospitaisFiltrados || HOSPITAIS;
  const meses = historico[HOSPITAIS[0].sigla];
  const n = meses.length;
  const nh = hospitaisExibidos.length;

  const largura = 760;
  const altura = 300;
  const margem = { top: 20, right: 24, bottom: 50, left: 56 };
  const innerW = largura - margem.left - margem.right;
  const innerH = altura - margem.top - margem.bottom;

  const todosValores = hospitaisExibidos.flatMap((h) => historico[h.sigla].map((d) => campoValor(d)));
  const maxAbs = Math.max(...todosValores.map((v) => Math.abs(v)), 1);
  const limite = maxAbs * 1.15;

  const yZero = margem.top + innerH * (limite / (2 * limite));
  const y = (v) => margem.top + innerH - ((v + limite) / (2 * limite)) * innerH;

  const larguraGrupo = innerW / n;
  const paddingGrupo = larguraGrupo * 0.15;
  const larguraBarra = (larguraGrupo - paddingGrupo * 2) / Math.max(nh, 1);

  const gridValues = [-limite, -limite / 2, 0, limite / 2, limite];

  return (
    <div className="overflow-x-auto">
      <svg viewBox={`0 0 ${largura} ${altura}`} className="w-full min-w-[600px]" role="img" aria-label={ariaLabel}>
        {/* grid horizontal */}
        {gridValues.map((v) => (
          <g key={v}>
            <line x1={margem.left} x2={largura - margem.right} y1={y(v)} y2={y(v)} stroke="#1C1A17" strokeOpacity={v === 0 ? 0.25 : 0.08} />
            <text x={margem.left - 8} y={y(v)} textAnchor="end" dominantBaseline="middle" className="font-mono-label" fontSize="9" fill="#6B6357">
              {formatarTick(v)}
            </text>
          </g>
        ))}

        {/* grupos por mês */}
        {meses.map((m, mi) => {
          const grupoX = margem.left + mi * larguraGrupo + paddingGrupo;
          return (
            <g key={m.label}>
              <text x={margem.left + mi * larguraGrupo + larguraGrupo / 2} y={altura - 30} textAnchor="middle" className="font-mono-label" fontSize="10" fill="#6B6357">
                {m.label}
              </text>
              {hospitaisExibidos.map((h, hi) => {
                const valor = campoValor(historico[h.sigla][mi]);
                const barX = grupoX + hi * larguraBarra;
                const barY = valor >= 0 ? y(valor) : y(0);
                const barH = Math.abs(y(valor) - y(0));
                const isSelected = pontoSelecionado && pontoSelecionado.sigla === h.sigla && pontoSelecionado.idx === mi;
                const cor = h.cor;
                return (
                  <rect
                    key={h.sigla}
                    x={barX}
                    y={barY}
                    width={Math.max(larguraBarra - 1.5, 1)}
                    height={Math.max(barH, 1)}
                    fill={cor}
                    opacity={isSelected ? 1 : 0.85}
                    stroke={isSelected ? "#1C1A17" : "none"}
                    strokeWidth={isSelected ? 1.5 : 0}
                    style={{ cursor: "pointer" }}
                    onClick={() => onSelecionarPonto({ sigla: h.sigla, idx: mi })}
                  />
                );
              })}
            </g>
          );
        })}

        {/* linha do zero, por cima das barras */}
        <line x1={margem.left} x2={largura - margem.right} y1={y(0)} y2={y(0)} stroke="#1C1A17" strokeOpacity="0.4" strokeWidth="1" />
      </svg>
    </div>
  );
}

