// ---------- Gráfico simples: 1 barra por hospital com o total acumulado ----------
function GraficoBarrasAcumulado({ acumulados }) {
  const largura = 760;
  const altura = 220;
  const margem = { top: 16, right: 24, bottom: 36, left: 80 };
  const innerW = largura - margem.left - margem.right;
  const innerH = altura - margem.top - margem.bottom;

  const maxAbs = Math.max(...acumulados.map((a) => Math.abs(a.total)), 1);
  const limite = maxAbs * 1.15;
  const y = (v) => margem.top + innerH - ((v + limite) / (2 * limite)) * innerH;

  const n = acumulados.length;
  const larguraGrupo = innerW / n;
  const larguraBarra = larguraGrupo * 0.55;

  return (
    <div className="overflow-x-auto">
      <svg viewBox={`0 0 ${largura} ${altura}`} className="w-full min-w-[420px]" role="img" aria-label="Economia acumulada no período, por hospital">
        {/* linha do zero */}
        <line x1={margem.left} x2={largura - margem.right} y1={y(0)} y2={y(0)} stroke="#1C1A17" strokeOpacity="0.4" strokeWidth="1" />

        {acumulados.map((a, i) => {
          const barX = margem.left + i * larguraGrupo + (larguraGrupo - larguraBarra) / 2;
          const barY = a.total >= 0 ? y(a.total) : y(0);
          const barH = Math.max(Math.abs(y(a.total) - y(0)), 1);
          return (
            <g key={a.hospital.sigla}>
              <rect
                x={barX}
                y={barY}
                width={larguraBarra}
                height={barH}
                fill={a.hospital.cor}
                opacity={0.9}
              />
              <text
                x={barX + larguraBarra / 2}
                y={a.total >= 0 ? barY - 6 : barY + barH + 14}
                textAnchor="middle"
                className="font-mono-label"
                fontSize="10"
                fill={a.total >= 0 ? "#1F5A4A" : "#A13D2B"}
              >
                {formatarMoeda(a.total)}
              </text>
              <text
                x={barX + larguraBarra / 2}
                y={altura - 12}
                textAnchor="middle"
                className="font-mono-label"
                fontSize="11"
                fontWeight="600"
                fill="#1C1A17"
              >
                {a.hospital.sigla}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}


// ---------- Tela: Economia prevista ----------
function AbaInserirConsumo() {
  const [aba, setAba] = useState("cadastro"); // "cadastro" | "referencia" | "custo"
  const [hospital, setHospital] = useState(HOSPITAIS[0].sigla);

  // Estado editável do realizado: { [hospitalSigla]: [ {mesIndex, ano, label, quantidades: {tipo: {catId: valor}}} ] }
  const [realizadoPorHospital, setRealizadoPorHospital] = useState(() => clonarRealizadoMock());

  // Quais meses já têm lançamento confirmado, por hospital. Os 6 primeiros meses do mock
  // simulam histórico já cadastrado; o mês mais recente começa em branco para demonstrar o fluxo.
  const [mesesCadastrados, setMesesCadastrados] = useState(() => {
    const inicial = {};
    HOSPITAIS.forEach((h) => {
      const totalMeses = REALIZADO_MOCK[h.sigla].length;
      inicial[h.sigla] = new Set(Array.from({ length: totalMeses - 1 }, (_, i) => i));
    });
    return inicial;
  });

  const referenciaHospital = REFERENCIA_MOCK[hospital];
  const realizadoHospital = realizadoPorHospital[hospital];
  const mesesCadastradosHospital = mesesCadastrados[hospital];

  function registrarLancamento(mesIdx, quantidadesPorTipoECategoria) {
    setRealizadoPorHospital((prev) => {
      const copia = { ...prev };
      copia[hospital] = copia[hospital].map((m, i) =>
        i === mesIdx ? { ...m, quantidades: quantidadesPorTipoECategoria } : m
      );
      return copia;
    });
    setMesesCadastrados((prev) => {
      const copia = { ...prev };
      copia[hospital] = new Set(prev[hospital]);
      copia[hospital].add(mesIdx);
      return copia;
    });
  }

  return (
    <main className="max-w-6xl mx-auto px-6 py-10">
        {/* Seletor de hospital + abas */}
        <div className="flex items-center justify-between flex-wrap gap-4 mb-6">
          <div className="flex border-2 border-[#1C1A17] flex-wrap">
            {[
              { id: "cadastro", label: "Cadastro do realizado" },
              { id: "referencia", label: "Referência de quantidade" },
              { id: "custo", label: "Custo unitário" },
            ].map((t, i) => (
              <button
                key={t.id}
                onClick={() => setAba(t.id)}
                className={`font-ui text-sm px-4 py-2.5 transition-colors ${i > 0 ? "border-l-2 border-[#1C1A17]" : ""}
                  ${aba === t.id ? "bg-[#1C1A17] text-[#EDE7D9]" : "bg-[#FAF7EF] text-[#1C1A17] hover:bg-[#E5DCC8]"}`}
              >
                {t.label}
              </button>
            ))}
          </div>

          <p className="font-mono-label text-[11px] text-[#6B6357]">
            UCI logada: <span className="text-[#1C1A17] font-semibold">{hospital}</span>
          </p>
        </div>

        {aba === "referencia" && <PainelReferencia referencia={referenciaHospital} />}
        {aba === "custo" && <PainelCusto />}
        {aba === "cadastro" && (
          <PainelCadastroRealizado
            key={hospital}
            referencia={referenciaHospital}
            realizadoHospital={realizadoHospital}
            mesesCadastrados={mesesCadastradosHospital}
            onRegistrar={registrarLancamento}
          />
        )}

        <p className="font-mono-label text-[10px] text-[#6B6357] mt-6 text-center">
          Protótipo — referência e custos exibidos com dados fictícios. Lançamentos não são salvos entre sessões.
          O resultado da economia é acompanhado no Painel.
        </p>
      </main>
  );
}

